   250	cxx20::expected<ArgumentParser::ArgumentDescriptor *, Error>
   251	ArgumentParser::SubCommandDescriptor::consume_short_options(
   252	    std::string_view Arg) noexcept {
   253	  ArgumentDescriptor *CurrentDesc = nullptr;
   254	  for (std::size_t I = 1; I < Arg.size(); ++I) {
   255	    if (CurrentDesc && CurrentDesc->nargs() == 0) {
   256	      CurrentDesc->default_value();
   257	    }
   258	    std::string_view Option = Arg.substr(I, 1);
   259	    if (auto Res = consume_short_option(Option); !Res) {
   260	      return cxx20::unexpected(Res.error());
   261	    } else {
   262	      CurrentDesc = *Res;
   263	    }
   264	  }
   265	  return CurrentDesc;
   266	}
   267	
   268	cxx20::expected<ArgumentParser::ArgumentDescriptor *, Error>
   269	ArgumentParser::SubCommandDescriptor::consume_long_option_with_argument(
   270	    std::string_view Arg) noexcept {
   271	  if (auto Pos = Arg.find('=', 2); Pos != std::string_view::npos) {
   272	    // long option with argument
   273	    std::string_view Option = Arg.substr(2, Pos - 2);
   274	    std::string_view Argument = Arg.substr(Pos + 1);
   275	    if (auto Res = consume_long_option(Option); !Res) {
   276	      return cxx20::unexpected<Error>(Res.error());
   277	    } else if (ArgumentDescriptor *CurrentDesc = *Res; !CurrentDesc) {
   278	      return cxx20::unexpected<Error>(std::in_place, ErrCode::InvalidArgument,
   279	                                      "option "s + std::string(Option) +
   280	                                          "doesn't need arguments."s);
   281	    } else {
   282	      consume_argument(*CurrentDesc, Argument);
   283	      return nullptr;
   284	    }
   285	  } else {
   286	    // long option without argument
   287	    std::string_view Option = Arg.substr(2);
   288	    return consume_long_option(Option);
   289	  }
   290	}
