   325	ArgumentParser::SubCommandDescriptor::consume_argument(
   326	    ArgumentDescriptor &CurrentDesc, std::string_view Argument) noexcept {
   327	  if (auto Res = CurrentDesc.argument(std::string(Argument)); !Res) {
