   336	bool ArgumentParser::parse(std::FILE *Out, int Argc,
   337	                           const char *Argv[]) noexcept {
   338	  if (auto Res = SubCommandDescriptors.front().parse(Out, {}, Argc, Argv, 0,
   339	                                                     VerOpt.value());
   340	      !Res) {
   341	    fmt::print(Out, "{}\n"sv, Res.error().message());
   342	    return false;
   343	  } else {
   344	    return *Res || VerOpt.value();
   345	  }
