   225	void ArgumentParser::SubCommandDescriptor::indent_output(
   226	    std::FILE *Out, const std::string_view kIndent, std::size_t IndentCount,
   227	    std::size_t ScreenWidth, std::string_view Desc) const noexcept {
   228	  const std::size_t Width = ScreenWidth - kIndent.size() * IndentCount;
   229	  while (Desc.size() > Width) {
   230	    const std::size_t SpacePos = Desc.find_last_of(' ', Width);
   231	    if (SpacePos != std::string_view::npos) {
   232	      for (std::size_t I = 0; I < IndentCount; ++I) {
   233	        fmt::print(Out, "{}"sv, kIndent);
   234	      }
   235	      fmt::print(Out, "{}\n"sv, Desc.substr(0, SpacePos));
   236	      const std::size_t WordPos = Desc.find_first_not_of(' ', SpacePos);
   237	      if (WordPos != std::string_view::npos) {
   238	        Desc = Desc.substr(WordPos);
   239	      } else {
   240	        Desc = {};
   241	      }
   242	    }
   243	  }
   244	  if (!Desc.empty()) {
   245	    for (std::size_t I = 0; I < IndentCount; ++I) {
   246	      fmt::print(Out, "{}"sv, kIndent);
   247	    }
   248	    fmt::print(Out, "{}"sv, Desc);
   249	  }
   250	}
