// Quick verification test for the numeric parser fix
#include "po/argument_parser.h"
#include "po/option.h"
#include <array>
#include <cstdio>
#include <iostream>

using namespace WasmEdge::PO;

int main() {
  int failures = 0;

  // Test 1: --b=100abc (equals form) should fail
  {
    Option<int> B(Description("b option"sv), DefaultValue<int>(-1));
    ArgumentParser Parser;
    Parser.add_option("b"sv, B);
    std::array<const char *, 3> Args = {"test", "--b=100abc"};
    bool result = Parser.parse(stdout, static_cast<int>(Args.size()), Args.data());
    if (result) {
      std::cerr << "FAIL: --b=100abc was accepted but should be rejected" << std::endl;
      failures++;
    } else {
      std::cout << "PASS: --b=100abc correctly rejected" << std::endl;
    }
  }

  // Test 2: --b 100abc (space form) should fail  
  {
    Option<int> B(Description("b option"sv), DefaultValue<int>(-1));
    ArgumentParser Parser;
    Parser.add_option("b"sv, B);
    std::array<const char *, 4> Args = {"test", "--b", "100abc"};
    bool result = Parser.parse(stdout, static_cast<int>(Args.size()), Args.data());
    if (result) {
      std::cerr << "FAIL: --b 100abc was accepted but should be rejected" << std::endl;
      failures++;
    } else {
      std::cout << "PASS: --b 100abc correctly rejected" << std::endl;
    }
  }

  // Test 3: --b=100 (valid value) should succeed
  {
    Option<int> B(Description("b option"sv), DefaultValue<int>(-1));
    ArgumentParser Parser;
    Parser.add_option("b"sv, B);
    std::array<const char *, 3> Args = {"test", "--b=100"};
    bool result = Parser.parse(stdout, static_cast<int>(Args.size()), Args.data());
    if (!result) {
      std::cerr << "FAIL: --b=100 was rejected but should be accepted" << std::endl;
      failures++;
    } else if (B.value() != 100) {
      std::cerr << "FAIL: --b=100 gave " << B.value() << " instead of 100" << std::endl;
      failures++;
    } else {
      std::cout << "PASS: --b=100 correctly accepted (value=" << B.value() << ")" << std::endl;
    }
  }

  // Test 4: --b 42 (valid value, space form) should succeed
  {
    Option<int> B(Description("b option"sv), DefaultValue<int>(-1));
    ArgumentParser Parser;
    Parser.add_option("b"sv, B);
    std::array<const char *, 4> Args = {"test", "--b", "42"};
    bool result = Parser.parse(stdout, static_cast<int>(Args.size()), Args.data());
    if (!result) {
      std::cerr << "FAIL: --b 42 was rejected but should be accepted" << std::endl;
      failures++;
    } else if (B.value() != 42) {
      std::cerr << "FAIL: --b 42 gave " << B.value() << " instead of 42" << std::endl;
      failures++;
    } else {
      std::cout << "PASS: --b 42 correctly accepted (value=" << B.value() << ")" << std::endl;
    }
  }

  // Test 5: --b=-2abc should fail (trailing garbage)
  {
    Option<int> B(Description("b option"sv), DefaultValue<int>(-1));
    ArgumentParser Parser;
    Parser.add_option("b"sv, B);
    std::array<const char *, 3> Args = {"test", "--b=-2abc"};
    bool result = Parser.parse(stdout, static_cast<int>(Args.size()), Args.data());
    if (result) {
      std::cerr << "FAIL: --b=-2abc was accepted but should be rejected" << std::endl;
      failures++;
    } else {
      std::cout << "PASS: --b=-2abc correctly rejected" << std::endl;
    }
  }

  // Test 6: --b=-2 (valid negative) should succeed
  {
    Option<int> B(Description("b option"sv), DefaultValue<int>(-1));
    ArgumentParser Parser;
    Parser.add_option("b"sv, B);
    std::array<const char *, 3> Args = {"test", "--b=-2"};
    bool result = Parser.parse(stdout, static_cast<int>(Args.size()), Args.data());
    if (!result) {
      std::cerr << "FAIL: --b=-2 was rejected but should be accepted" << std::endl;
      failures++;
    } else if (B.value() != -2) {
      std::cerr << "FAIL: --b=-2 gave " << B.value() << " instead of -2" << std::endl;
      failures++;
    } else {
      std::cout << "PASS: --b=-2 correctly accepted (value=" << B.value() << ")" << std::endl;
    }
  }

  // Test 7: --b=-  (just minus sign) should fail
  {
    Option<int> B(Description("b option"sv), DefaultValue<int>(-1));
    ArgumentParser Parser;
    Parser.add_option("b"sv, B);
    std::array<const char *, 3> Args = {"test", "--b=-"};
    bool result = Parser.parse(stdout, static_cast<int>(Args.size()), Args.data());
    if (result) {
      std::cerr << "FAIL: --b=- was accepted but should be rejected" << std::endl;
      failures++;
    } else {
      std::cout << "PASS: --b=- correctly rejected" << std::endl;
    }
  }

  // Test 8: Empty string should fail
  {
    Option<int> B(Description("b option"sv), DefaultValue<int>(-1));
    ArgumentParser Parser;
    Parser.add_option("b"sv, B);
    std::array<const char *, 3> Args = {"test", "--b="};
    bool result = Parser.parse(stdout, static_cast<int>(Args.size()), Args.data());
    if (result) {
      std::cerr << "FAIL: --b= was accepted but should be rejected" << std::endl;
      failures++;
    } else {
      std::cout << "PASS: --b= correctly rejected" << std::endl;
    }
  }

  std::cout << "\n" << failures << " failure(s) total." << std::endl;
  return failures;
}

